import { RuleSet, css } from 'styled-components';

import { base } from '#theme/colors';
import * as device from '#theme/devices';
import { primaryFont, secondaryFont } from '#theme/fontFamilies';

/**
 * CSS to fully hide elements of the page
 */
const hidden = css`
  display: none;
`;

/**
 * CSS to visually hide semantically necessary elements of the page
 */
const visuallyHidden = css`
  position: absolute;
  overflow: hidden;
  width: 0.01em;
  height: 0.01em;
  padding: 0;
  border: none;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
`;

/**
 * Wraps provided declarations in a media query given a feature
 * @param {string} feature Feature to match against
 * @param {string} declarations CSS declarations to apply
 * @returns {string} CSS containing declarations wrapped in a media query
 */
function mq(feature: string, declarations: RuleSet<object>) {
  if (!Object.values(device).includes(feature)) {
    console.warn(`No such feature: "${feature}"`);
    return null;
  }

  return css`
    @media ${feature} {
      ${declarations}
    }
  `;
}

/**
 * Returns CSS required to hide an element on the page
 * @param {string} [feature] Feature to match against to hide elements
 * @returns {string} CSS containing declarations wrapped in a media query
 */
function hiddenOn(feature: string) {
  return mq(feature, hidden);
}

/**
 * Returns CSS required to visually hide an element on the page
 * @param {string} [feature] Feature to match against to hide elements
 * @returns {string} CSS containing declarations wrapped in a media query
 */
function visuallyHiddenOn(feature: string) {
  return mq(feature, visuallyHidden);
}

const anchorLink = css`
  color: ${base.actionBrand.base};

  &:hover {
    color: ${base.actionBrand.alt};
  }
`;

const tag = {
  small: css`
    font: bold 14px/18px ${secondaryFont};
    letter-spacing: 2.5px;
    text-transform: uppercase;
  `,
  medium: css`
    font: bold 16px/20px ${secondaryFont};
    letter-spacing: 2.5px;
    text-transform: uppercase;
  `,
  large: css`
    font: bold 18px/22px ${secondaryFont};
    letter-spacing: 2.5px;
    text-transform: uppercase;
  `,
};

const typography = {
  tag,
  recommendedLinks: css`
    ${anchorLink};
    font: bold 18px/22px ${primaryFont};
  `,
};

export {
  hidden,
  visuallyHidden,
  hiddenOn,
  visuallyHiddenOn,
  anchorLink,
  typography,
};
